def atan_regularization(raw_value, k):
    return torch.atan(k * raw_value) / np.pi # + 0.5, this sets a atan whose range is -1 to 1.0

def sigmoid_regularitzation(raw_value, k):
    return k * torch.sigmoid(raw_value)

#############################################################################
#############################################################################
#############################################################################
#############################################################################

class KANStressPredictor(nn.Module):

    def __init__(self):
        super(KANStressPredictor, self).__init__()

        # new ones
        self.kappa = torch.tensor(0.0) # dissipation
        self.q = torch.tensor(0.0)     # plastic strain

        # n-1
        self.old_kappa = torch.tensor(0.0) # dissipation
        self.old_q = torch.tensor(0.0)     # plastic strain

        self.model_psi = KAN.MultKAN( # eps, q, kappa --> psi // stress = grad.psi
            width=[3, 2, 1],
            grid=3,
            k=2,
            grid_range=[0, 1]
        )
        self.model_psi.speed()

        self.model_F = KAN.MultKAN( # eps, kappa --> F
            width=[2, 2, 1],
            grid=3,
            k=2,
            grid_range=[0, 1]
        )
        self.model_F.speed()

    # ----------------------------------------------------------------------------------
    def CalculateStress(self, strain): # returns stress with q and kappa from memory

        psi_KAN_inputs = []
        psi_KAN_inputs.append(strain)
        psi_KAN_inputs.append(torch.full_like(strain, self.old_q))
        psi_KAN_inputs.append(torch.full_like(strain, self.old_kappa))

        KAN_input = torch.cat(psi_KAN_inputs, dim=-1)

        # This method computes the stress without updating internal vars
        zeros = [torch.zeros_like(strain, requires_grad=True), torch.full_like(strain, self.old_q), torch.full_like(strain, self.old_kappa)]
        KAN_zeros = torch.cat(zeros, dim=-1) # The null input is strain zero and int vars whatever is in memory!

        raw_psi = self.model_psi(KAN_input)
        psi_at_0 = self.model_psi(KAN_zeros)
        
        grad_0 = torch.autograd.grad(
            outputs=psi_at_0,
            inputs=KAN_zeros,
            grad_outputs=torch.ones_like(psi_at_0),
            create_graph=True
        )[0]

        grad = torch.autograd.grad(
            outputs=raw_psi,
            inputs=strain,
            grad_outputs=torch.ones_like(raw_psi),
            create_graph=True
        )[0]

        return grad - grad_0[:, :1] # grad_0[:, :1] selects the first column of strain, shape (100, 1)

    # ----------------------------------------------------------------------------------
    def CalculateSecondDerivativesPsi(self, strain): # d2psi/dE, d2Psi/dE dq
        
        q_for_grad = self.old_q.detach().requires_grad_(True)
        # Compute psi as function of strain
        psi_KAN_inputs = []
        psi_KAN_inputs.append(strain)
        # psi_KAN_inputs.append(torch.full_like(strain, q_for_grad))
        psi_KAN_inputs.append(q_for_grad.expand_as(strain))
        psi_KAN_inputs.append(torch.full_like(strain, self.old_kappa))

        KAN_input = torch.cat(psi_KAN_inputs, dim=-1)

        raw_psi = self.model_psi(KAN_input)

        # First derivative: stress = d(psi)/d(strain)
        stress = torch.autograd.grad(
            outputs=raw_psi,
            inputs=strain,
            grad_outputs=torch.ones_like(raw_psi),
            create_graph=True,
        )[0]

        # Second derivative: C = d(stress)/d(strain) = d²(psi)/d(strain)²
        C = torch.autograd.grad(
            outputs=stress,
            inputs=strain,
            grad_outputs=torch.ones_like(stress),
            create_graph=True)[0]

        d2Psi_dE_dq = torch.autograd.grad(
            outputs=stress,
            inputs=q_for_grad,
            grad_outputs=torch.ones_like(stress),
            create_graph=True)[0]
        
        return C, d2Psi_dE_dq

    # ----------------------------------------------------------------------------------
    def CalculateFandDerivatives(self, strain):

        stress = self.CalculateStress(strain)
        # keep kappa as internal state, but allow grad for this sensitivity computation
        kappa_for_grad = self.old_kappa.detach().requires_grad_(True)

        F_KAN_inputs = []
        F_KAN_inputs.append(stress) # Stress
        F_KAN_inputs.append(kappa_for_grad.expand_as(strain)) # kappa
        KAN_input = torch.cat(F_KAN_inputs, dim=-1)

        raw_F = self.model_F(KAN_input)

        zeros = [torch.zeros_like(strain, requires_grad=True), torch.full_like(strain, self.old_kappa)]
        KAN_zeros = torch.cat(zeros, dim=-1) # The null input is strain zero and int vars whatever is in memory!
        F_at_zeros = self.model_F(torch.zeros_like(KAN_zeros, requires_grad=True))

        dF_d_stress = torch.autograd.grad(
            outputs=raw_F,
            inputs=stress,
            grad_outputs=torch.ones_like(raw_F),
            create_graph=True,
            retain_graph=True,
            allow_unused=False,
        )[0]

        dF_d_kappa = torch.autograd.grad(
            outputs=raw_F,
            inputs=kappa_for_grad,
            grad_outputs=torch.ones_like(raw_F),
            create_graph=True,
            retain_graph=True,
            allow_unused=False,
        )[0]

        return raw_F - F_at_zeros, dF_d_stress, dF_d_kappa

    # ----------------------------------------------------------------------------------
    def forward(self, strain):

        strain = strain.detach().requires_grad_(True)

        stress = self.CalculateStress(strain) # predicts with old int vars and curr E

        raw_F, dF_d_stress, dF_d_kappa = self.CalculateFandDerivatives(strain)
        
        C, d2Psi_dE_dq = self.CalculateSecondDerivativesPsi(strain)

        k = 10
        gamma = sigmoid_regularitzation(raw_F / (dF_d_stress * d2Psi_dE_dq - dF_d_kappa**2), k) # we regularise the F condition in here
        dq = atan_regularization(-gamma * dF_d_stress, k / 10)
        dkappa = sigmoid_regularitzation(gamma * dF_d_kappa, k)

        # scalar internal update to avoid shape mismatch
        self.old_q = (self.old_q + dq.mean()).detach()
        self.old_kappa = (self.old_kappa + dkappa.mean()).detach()

        stress = self.CalculateStress(strain)

        self.old_q = (self.old_q - dq.mean()).detach()
        self.old_kappa = (self.old_kappa - dkappa.mean()).detach()

        # if raw_F.item() > 0.0:
        #     accum_q = 0.0
        #     accum_kappa = 0.0
        #     max_iter = 50
        #     iter = 0
        #     while raw_F.item() > 0.0 and iter < max_iter:
        #         C, d2Psi_dE_dq = self.CalculateSecondDerivativesPsi(strain)
        #         gamma = raw_F / (dF_d_stress * d2Psi_dE_dq - dF_d_kappa**2)
        #         if gamma < 0.0:
        #             break
        #         dq = -gamma * dF_d_stress
        #         dkappa = gamma * dF_d_kappa

        #         # scalar internal update to avoid shape mismatch
        #         self.old_q = (self.old_q + dq.mean()).detach()
        #         self.old_kappa = (self.old_kappa + dkappa.mean()).detach()
                
        #         accum_q += dq.mean()
        #         accum_kappa += dkappa.mean()

        #         stress = self.CalculateStress(strain)
        #         raw_F, dF_d_stress, dF_d_kappa = self.CalculateFandDerivatives(strain)
        #         iter += 1

        #     # we cancel the increment, to be done in finalize
        #     self.old_q = (self.old_q - accum_q).detach()
        #     self.old_kappa = (self.old_kappa - accum_kappa).detach()

        return stress

    # ----------------------------------------------------------------------------------
    def FinalizeMaterialResponse(self, strain):

        strain = strain.detach().requires_grad_(True)

        stress = self.CalculateStress(strain) # predicts with old int vars and curr E

        raw_F, dF_d_stress, dF_d_kappa = self.CalculateFandDerivatives(strain)

        C, d2Psi_dE_dq = self.CalculateSecondDerivativesPsi(strain)

        k = 10
        gamma = sigmoid_regularitzation(raw_F / (dF_d_stress * d2Psi_dE_dq - dF_d_kappa**2), k) # we regularise the F condition in here
        dq = atan_regularization(-gamma * dF_d_stress, k / 10)
        dkappa = sigmoid_regularitzation(gamma * dF_d_kappa, k)

        # scalar internal update to avoid shape mismatch
        self.old_q = (self.old_q + dq.mean()).detach()
        self.old_kappa = (self.old_kappa + dkappa.mean()).detach()




        # strain = strain.detach().requires_grad_(True)

        # stress = self.CalculateStress(strain) # predicts with old int vars and curr E

        # raw_F, dF_d_stress, dF_d_kappa = self.CalculateFandDerivatives(strain)
        # if raw_F.item() > 0.0:
        #     max_iter = 50
        #     iter = 0
        #     while raw_F.item() > 0.0 and iter < max_iter:
        #         C, d2Psi_dE_dq = self.CalculateSecondDerivativesPsi(strain)
        #         gamma = raw_F / (dF_d_stress * d2Psi_dE_dq - dF_d_kappa**2)
        #         if gamma < 0.0:
        #             break
        #         dq = -gamma * dF_d_stress
        #         dkappa = gamma * dF_d_kappa

        #         # scalar internal update to avoid shape mismatch
        #         self.old_q = (self.old_q + dq.mean()).detach()
        #         self.old_kappa = (self.old_kappa + dkappa.mean()).detach()

        #         stress = self.CalculateStress(strain)
        #         raw_F, dF_d_stress, dF_d_kappa = self.CalculateFandDerivatives(strain)
        #         iter += 1

    # ----------------------------------------------------------------------------------
    def ResetInternalVars(self):
        self.old_kappa = torch.tensor(0.0) # dissipation
        self.old_q = torch.tensor(0.0)     # plastic strain

#############################################################################
#############################################################################
#############################################################################
#############################################################################


model = KANStressPredictor()

# null value at origin check
null_var = torch.tensor([[0.0]])
print("Before training: ")
print("model(0)= ", model.forward(null_var), "\n")

optimizer = torch.optim.Adam(model.parameters(), lr=0.01)

x_torch = torch.tensor(eps, dtype=torch.float32).unsqueeze(1)  # (steps,1)
y_torch = torch.tensor(sigma, dtype=torch.float32).unsqueeze(1)  # (steps,1)
zeros = torch.zeros_like(x_torch)

n_epochs = 100

for epoch in range(n_epochs):
    optimizer.zero_grad()

    vectorized = False

    if vectorized:
        y_pred = model(x_torch)  # shape (100,1)
    else:
        y_pred_list = []
        for i in range(len(x_torch)):
            x_i = x_torch[i].view(1, 1)  # already tensor, no need to recreate
            y_pred_i = model.forward(x_i)        # keep tensor with grad
            y_pred_list.append(y_pred_i)
            model.FinalizeMaterialResponse(x_i)

        # Stack into a tensor
        model.ResetInternalVars()
        y_pred = torch.vstack(y_pred_list)  # shape (100,1)


    # L2 loss
    loss = torch.mean((y_pred - y_torch)**2)

    loss.backward()
    optimizer.step()

    if epoch % 2 == 0:
        print(f"Epoch {epoch}, Loss: {loss.item()}")











# plot the KAN
y_pred_list = []
kappa_list = []
q_list = []
eps = data["eps"][0:100]  # we take the whole dataset for plot
eps = eps / eps_max
x_torch = torch.tensor(eps, dtype=torch.float32).unsqueeze(1)
for i in range(len(x_torch)):
    x_i = x_torch[i].view(1, 1)  # already tensor, no need to recreate
    y_pred_i = model.forward(x_i)        # keep tensor with grad
    model.FinalizeMaterialResponse(x_i)
    y_pred_list.append(y_pred_i)
    kappa_list.append(model.old_kappa)
    q_list.append(model.old_q)
model.ResetInternalVars()

# Convert stacked tensor predictions to numpy
y_pred = torch.vstack(y_pred_list)
kappa_pred = torch.vstack(kappa_list)
kappa_plot = kappa_pred.detach().cpu().numpy()
q_pred = torch.vstack(q_list)
q_plot = q_pred.detach().cpu().numpy()
y_KAN = y_pred.detach().cpu().numpy()

plt.plot(eps, y_KAN, '--', color="k", label='KAN (trained)')
plt.legend()
plt.grid()
plt.show()

